import { withDb } from "./db.mjs";

// Enterprise schema: 21 collections with embedded arrays.
// This creates the full 40-entity domain as MongoDB collections.
export async function ensureSchema(db) {
  const { generateMongoSchema } = await import("../scripts/enterprise-schema-gen.mjs");
  const gen = generateMongoSchema();
  await gen.ensureSchema(db);

  // Add preferredPaymentMethod to the accounts collection validator if it uses
  // a strict $jsonSchema validator that doesn't already include the field.
  try {
    const collections = await db.listCollections({ name: "accounts" }).toArray();
    if (collections.length > 0) {
      const options = collections[0].options || {};
      const schema = options.validator?.$jsonSchema;
      if (schema && !schema.properties?.preferredPaymentMethod) {
        await db.command({
          collMod: "accounts",
          validator: {
            $jsonSchema: {
              ...schema,
              properties: {
                ...schema.properties,
                preferredPaymentMethod: {
                  bsonType: "string",
                  enum: ["card", "bank_transfer", "check", "wire"],
                },
              },
            },
          },
          validationLevel: "moderate",
        });
      }
    }
  } catch (e) {
    // collMod failure is non-fatal: existing documents remain valid.
    console.warn("Warning: could not update accounts validator:", e.message);
  }
}

